e9af1af7-1eef-44c9-9b86-6c6cd7225fb2	congress.gov	119-HR-1125	https://www.congress.gov/bill/119th-congress/house-bill/1125	119	HR	1125	LOCAL Act	2025-02-07	House	Public Lands and Natural Resources	2025-02-07	Referred to the House Committee on Natural Resources.	2025-05-06 12:40:22	2025-05-06 12:40:22	bc5930ada9142d5c05c4f8947d52558ea6742d2c63cd9f70e12af38635912269	{"type": "HR", "title": "LOCAL Act", "number": "1125", "titles": {"url": "https://api.congress.gov/v3/bill/119/hr/1125/titles?format=json", "count": 4}, "actions": {"url": "https://api.congress.gov/v3/bill/119/hr/1125/actions?format=json", "count": 3}, "congress": 119, "sponsors": [{"url": "https://api.congress.gov/v3/member/H001100?format=json", "party": "R", "state": "CO", "district": 3, "fullName": "Rep. Hurd, Jeff [R-CO-3]", "lastName": "Hurd", "firstName": "Jeff", "bioguideId": "H001100", "isByRequest": "N"}], "subjects": {"url": "https://api.congress.gov/v3/bill/119/hr/1125/subjects?format=json", "count": 22}, "committees": {"url": "https://api.congress.gov/v3/bill/119/hr/1125/committees?format=json", "count": 1}, "cosponsors": {"url": "https://api.congress.gov/v3/bill/119/hr/1125/cosponsors?format=json", "count": 17, "countIncludingWithdrawnCosponsors": 17}, "policyArea": {"name": "Public Lands and Natural Resources"}, "updateDate": "2025-05-06T12:40:22Z", "latestAction": {"text": "Referred to the House Committee on Natural Resources.", "actionDate": "2025-02-07"}, "textVersions": {"url": "https://api.congress.gov/v3/bill/119/hr/1125/text?format=json", "count": 1}, "originChamber": "House", "introducedDate": "2025-02-07", "legislationUrl": "https://www.congress.gov/bill/119th-congress/house-bill/1125", "originChamberCode": "H", "updateDateIncludingText": "2025-05-06T12:40:22Z", "constitutionalAuthorityStatementText": "<pre>\\n[Congressional Record Volume 171, Number 26 (Friday, February 7, 2025)]\\n[House]\\nFrom the Congressional Record Online through the Government Publishing Office [<a href=\\"https://www.gpo.gov\\">www.gpo.gov</a>]\\nBy Mr. HURD of Colorado:\\nH.R. 1125.\\nCongress has the power to enact this legislation pursuant\\nto the following:\\nArticle IV, Section 3, Clause 2 (the Property Clause).\\nUnder this clause, Congress has the power to dispose of and\\nmake all needful rules and regulations respecting the\\nterritory or other property belonging to the United States.\\nBy virtue of this enumerated power, Congress has governing\\nauthority over the lands, territories, or other property of\\nthe United States--and with this authority Congress is vested\\nwith the power to all owners in fee, the ability to sell,\\nlease, dispose, exchange, convey, or simply preserve land.\\nArticle 1, Section 8, clause 18 (the Necessary and Proper\\nClause). Under this clause, Congress has the power to make\\nall Laws which shall be necessary and proper for carrying\\ninto Execution the foregoing Powers, and all other Powers\\nvested by this Constitution in the Government of the United\\nStates, or in any Department or Officer thereof.\\n[Page H585]\\n</pre>"}	2026-06-03 12:23:03.040489	2026-06-03 12:23:03.040489
