150dd5fd-fa17-41d2-a375-254d7fa9cbc5	congress.gov	119-HR-4553	https://www.congress.gov/bill/119th-congress/house-bill/4553	119	HR	4553	Energy and Water Development and Related Agencies Appropriations Act, 2026	2025-07-21	House	Economics and Public Finance	2025-09-10	Read the second time. Placed on Senate Legislative Calendar under General Orders. Calendar No. 156.	2026-03-10 12:51:45	2026-03-10 12:51:45	15c5d497d70e380db3c91357af6f6ecf727823dd91ea43fcc437dcdbd2a90ff6	{"type": "HR", "title": "Energy and Water Development and Related Agencies Appropriations Act, 2026", "number": "4553", "titles": {"url": "https://api.congress.gov/v3/bill/119/hr/4553/titles?format=json", "count": 5}, "actions": {"url": "https://api.congress.gov/v3/bill/119/hr/4553/actions?format=json", "count": 56}, "congress": 119, "sponsors": [{"url": "https://api.congress.gov/v3/member/F000459?format=json", "party": "R", "state": "TN", "district": 3, "fullName": "Rep. Fleischmann, Charles J. \\"Chuck\\" [R-TN-3]", "lastName": "Fleischmann", "firstName": "Charles", "bioguideId": "F000459", "middleName": "J. \\"Chuck\\"", "isByRequest": "N"}], "subjects": {"url": "https://api.congress.gov/v3/bill/119/hr/4553/subjects?format=json", "count": 88}, "summaries": {"url": "https://api.congress.gov/v3/bill/119/hr/4553/summaries?format=json", "count": 1}, "amendments": {"url": "https://api.congress.gov/v3/bill/119/hr/4553/amendments?format=json", "count": 16}, "committees": {"url": "https://api.congress.gov/v3/bill/119/hr/4553/committees?format=json", "count": 1}, "policyArea": {"name": "Economics and Public Finance"}, "updateDate": "2026-03-10T12:51:45Z", "latestAction": {"text": "Read the second time. Placed on Senate Legislative Calendar under General Orders. Calendar No. 156.", "actionDate": "2025-09-10"}, "relatedBills": {"url": "https://api.congress.gov/v3/bill/119/hr/4553/relatedbills?format=json", "count": 4}, "textVersions": {"url": "https://api.congress.gov/v3/bill/119/hr/4553/text?format=json", "count": 3}, "originChamber": "House", "introducedDate": "2025-07-21", "legislationUrl": "https://www.congress.gov/bill/119th-congress/house-bill/4553", "committeeReports": [{"url": "https://api.congress.gov/v3/committee-report/119/HRPT/213?format=json", "citation": "H. Rept. 119-213"}], "originChamberCode": "H", "updateDateIncludingText": "2026-03-10T12:51:45Z", "constitutionalAuthorityStatementText": "<pre>\\n[Congressional Record Volume 171, Number 124 (Monday, July 21, 2025)]\\n[House]\\nFrom the Congressional Record Online through the Government Publishing Office [<a href=\\"https://www.gpo.gov\\">www.gpo.gov</a>]\\nBy Mr. FLEISCHMANN:\\nH.R. 4553.\\nCongress has the power to enact this legislation pursuant\\nto the following:\\nThe principal constitutional authority for this legislation\\nis clause 7 of section 9 of article I of the Constitution of\\nthe United States (the appropriation power), which states:\\n``No Money shall be drawn from the Treasury, but in\\nConsequence of Appropriations made by Law. . . .'' In\\naddition, clause 1 of section 8 of article I of the\\nConstitution (the spending power) provides: ``The Congress\\nshall have the Power . . . to pay the Debts and provide for\\nthe common Defence and general Welfare of the United States.\\n. . .'' Together, these specific constitutional provisions\\nestablish the congressional power of the purse, granting\\nCongress the authority to appropriate funds, to determine\\ntheir purpose, amount, and period of availability, and to set\\nforth terms and conditions governing their use.\\n[Page H3527]\\n</pre>"}	2026-06-03 14:43:59.374452	2026-06-03 14:43:59.374452
