30f19615-fda5-4388-9466-d54ce46eaabc	congress.gov	119-HR-5694	https://www.congress.gov/bill/119th-congress/house-bill/5694	119	HR	5694	ARTIST Act	2025-10-06	House	Native Americans	2026-06-02	Placed on the Union Calendar, Calendar No. 588.	2026-06-03 08:08:38	2026-06-03 08:08:38	4c7dabe498d77c0133333972df1fcabbb9600cc947cc8ebade339a0d96c9319a	{"type": "HR", "title": "ARTIST Act", "number": "5694", "titles": {"url": "https://api.congress.gov/v3/bill/119/hr/5694/titles?format=json", "count": 6}, "actions": {"url": "https://api.congress.gov/v3/bill/119/hr/5694/actions?format=json", "count": 11}, "congress": 119, "sponsors": [{"url": "https://api.congress.gov/v3/member/B001323?format=json", "party": "R", "state": "AK", "fullName": "Rep. Begich, Nicholas J. [R-AK-At Large]", "lastName": "Begich", "firstName": "Nicholas", "bioguideId": "B001323", "middleName": "J.", "isByRequest": "N"}], "subjects": {"url": "https://api.congress.gov/v3/bill/119/hr/5694/subjects?format=json", "count": 6}, "summaries": {"url": "https://api.congress.gov/v3/bill/119/hr/5694/summaries?format=json", "count": 1}, "committees": {"url": "https://api.congress.gov/v3/bill/119/hr/5694/committees?format=json", "count": 1}, "policyArea": {"name": "Native Americans"}, "updateDate": "2026-06-03T08:08:38Z", "latestAction": {"text": "Placed on the Union Calendar, Calendar No. 588.", "actionDate": "2026-06-02"}, "relatedBills": {"url": "https://api.congress.gov/v3/bill/119/hr/5694/relatedbills?format=json", "count": 1}, "textVersions": {"url": "https://api.congress.gov/v3/bill/119/hr/5694/text?format=json", "count": 2}, "originChamber": "House", "introducedDate": "2025-10-06", "legislationUrl": "https://www.congress.gov/bill/119th-congress/house-bill/5694", "originChamberCode": "H", "updateDateIncludingText": "2026-06-03T08:08:38Z", "constitutionalAuthorityStatementText": "<pre>\\n[Congressional Record Volume 171, Number 164 (Monday, October 6, 2025)]\\n[House]\\nFrom the Congressional Record Online through the Government Publishing Office [<a href=\\"https://www.gpo.gov\\">www.gpo.gov</a>]\\nBy Mr. BEGICH:\\nH.R. 5694.\\nCongress has the power to enact this legislation pursuant\\nto the following:\\nPursuant to clause 7 of rule XII of the Rules of the House\\nof Representatives, the Congress finds the authority for this\\nlegislation in the following provisions of the Constitution:\\nArticle I, Section 8, Clause 3--The Congress shall have Power\\nTo regulate Commerce with foreign Nations, and among the\\nseveral States, and with the Indian Tribes. This clause\\ngrants Congress the authority to regulate interstate and\\ntribal commerce, including the trade and sale of marine\\nmammal products and Alaska Native handicrafts derived\\ntherefrom. The bill amends the Marine Mammal Protection Act\\nof 1972 to clarify and protect lawful Alaska Native commerce\\nin traditional handicrafts and ivory products, and to ensure\\nconsistent federal standards governing such trade across\\nstate lines and tribal jurisdictions.\\n[Page H4523]\\n</pre>"}	2026-06-03 15:04:51.47622	2026-06-03 15:04:51.47622
