594f2cc7-9d29-4f37-b725-3670013306d6	congress.gov	119-HR-8469	https://www.congress.gov/bill/119th-congress/house-bill/8469	119	HR	8469	Making appropriations for military construction, the Department of Veterans Affairs, and related agencies for the fiscal year ending September 30, 2027, and for other purposes.	2026-04-23	House	Economics and Public Finance	2026-05-20	Received in the Senate.	2026-05-27 18:23:35	2026-05-28 02:18:26	5f911b0f5c6284895c36e5bfbed34f1c1f5b81c9340d2906a25d36867623adfe	{"type": "HR", "title": "Making appropriations for military construction, the Department of Veterans Affairs, and related agencies for the fiscal year ending September 30, 2027, and for other purposes.", "number": "8469", "titles": {"url": "https://api.congress.gov/v3/bill/119/hr/8469/titles?format=json", "count": 5}, "actions": {"url": "https://api.congress.gov/v3/bill/119/hr/8469/actions?format=json", "count": 28}, "congress": 119, "sponsors": [{"url": "https://api.congress.gov/v3/member/C001051?format=json", "party": "R", "state": "TX", "district": 31, "fullName": "Rep. Carter, John R. [R-TX-31]", "lastName": "Carter", "firstName": "John", "bioguideId": "C001051", "middleName": "R.", "isByRequest": "N"}], "subjects": {"url": "https://api.congress.gov/v3/bill/119/hr/8469/subjects?format=json", "count": 61}, "summaries": {"url": "https://api.congress.gov/v3/bill/119/hr/8469/summaries?format=json", "count": 1}, "amendments": {"url": "https://api.congress.gov/v3/bill/119/hr/8469/amendments?format=json", "count": 6}, "committees": {"url": "https://api.congress.gov/v3/bill/119/hr/8469/committees?format=json", "count": 1}, "policyArea": {"name": "Economics and Public Finance"}, "updateDate": "2026-05-27T18:23:35Z", "latestAction": {"text": "Received in the Senate.", "actionDate": "2026-05-20"}, "relatedBills": {"url": "https://api.congress.gov/v3/bill/119/hr/8469/relatedbills?format=json", "count": 1}, "textVersions": {"url": "https://api.congress.gov/v3/bill/119/hr/8469/text?format=json", "count": 2}, "originChamber": "House", "introducedDate": "2026-04-23", "legislationUrl": "https://www.congress.gov/bill/119th-congress/house-bill/8469", "committeeReports": [{"url": "https://api.congress.gov/v3/committee-report/119/HRPT/622?format=json", "citation": "H. Rept. 119-622"}], "originChamberCode": "H", "updateDateIncludingText": "2026-05-28T02:18:26Z", "constitutionalAuthorityStatementText": "<pre>\\n[Congressional Record Volume 172, Number 72 (Thursday, April 23, 2026)]\\n[House]\\nFrom the Congressional Record Online through the Government Publishing Office [<a href=\\"https://www.gpo.gov\\">www.gpo.gov</a>]\\nBy Mr. CARTER:\\nH.R. 8469.\\nCongress has the power to enact this legislation pursuant\\nto the following:\\nThe principal constitutional authority for this legislation\\nis clause 7 of section 9 of article I of the Constitution of\\nthe United States (the appropriation power), which states:\\n``No Money shall be drawn from the Treasury, but in\\nConsequence of Appropriations made by Law . . . .'' In\\naddition, clause 1 of section 8 of article I of the\\nConstitution (the spending power) provides: ``The Congress\\nshall have the Power . . . to pay the Debts and provide for\\nthe common Defence and general Welfare of the United States .\\n. . .'' Together, these specific constitutional provisions\\nestablish the congressional power of the purse, granting\\nCongress the authority to appropriate funds, to determine\\ntheir purpose, amount, and period of availability, and to set\\nforth terms and conditions governing their use.\\n[Page H3092]\\n</pre>"}	2026-06-03 15:54:39.713156	2026-06-03 15:54:39.713156
